DELETE FROM $$STGDB.SCMS_FINAL;
CREATE MULTISET volatile TABLE SCMS_RMA AS 
(
SELECT RMA.FISCAL_YEAR_MONTH_INT,SRC_RPTD_SR_NUMBER_INT,DV_END_CUSTOMER_NAME,C3_CUSTOMER_THEATER_NAME,SRC_RPTD_SITE_CNTRY_NAME,RMA.C3_CUST_MARKET_SEGMENT_NAME,
RMA.EDW_CREATE_DTM,SUM(SSC_DPT_PRSNL_RSRC_CST_USD_AMT+SSC_DEPRECIATION_COST_USD_AMT
+SSC_REPAIR_COST_USD_AMT+SSC_DUTY_VAT_COST_USD_AMT     
+SSC_THRD_PRTY_LGST_CST_USD_AMT+SSC_THRD_PRTY_MTNC_CST_USD_AMT
+SSC_ORIG_EQP_MFGR_CST_USD_AMT)  AS SSC_COST
FROM $$FINLGLVWDB.N_SR_SRVC_SUPPORT_CENTER_COST RMA
INNER JOIN $$STGDB.WI_CCM_TS_MTH_QTR_CNTL CNTL
ON CNTL.FISCAL_YEAR_MONTH_INT = RMA.FISCAL_YEAR_MONTH_INT
group by 1,2,3,4,5,6,7
)  WITH DATA ON COMMIT PRESERVE ROWS; 

collect stats on SCMS_RMA column(FISCAL_YEAR_MONTH_INT);
collect stats on SCMS_RMA column(SRC_RPTD_SITE_CNTRY_NAME);
collect stats on SCMS_RMA column(C3_CUSTOMER_THEATER_NAME);
collect stats on SCMS_RMA column(C3_CUST_MARKET_SEGMENT_NAME);
collect stats on SCMS_RMA column(DV_END_CUSTOMER_NAME);
collect stats on SCMS_RMA column(SRC_RPTD_SR_NUMBER_INT);

CREATE MULTISET VOLATILE TABLE SCMS_SR AS  /*Added this on 27/04/2021 to check market segment key from RMA to SR based on end customer*/
(

SELECT SR.FISCAL_YEAR_MONTH_INT,SRC_RPTD_SR_NUMBER_INT,DV_END_CUSTOMER_NAME,C3_CUSTOMER_THEATER_NAME,SOURCE_REPORTED_TAC_COUNTRY_CD
,SR.C3_CUST_MARKET_SEGMENT_NAME,SR.EDW_CREATE_DTM,sum(TAC_BACKBONE_COST_USD_AMT+TAC_THTR_BIZ_OPRTN_CST_USD_AMT
+TAC_OUT_TASKING_COST_AMT+TAC_OVERHEAD_COST_USD_AMT) as tac_cost     
FROM $$FINLGLVWDB.N_SR_TECH_ASSISTANCE_CNTR_COST SR
INNER JOIN $$STGDB.WI_CCM_TS_MTH_QTR_CNTL CNTL
ON CNTL.FISCAL_YEAR_MONTH_INT = SR.FISCAL_YEAR_MONTH_INT
group by 1,2,3,4,5,6,7
)  WITH DATA ON COMMIT PRESERVE ROWS;  --0

collect stats on SCMS_SR column(FISCAL_YEAR_MONTH_INT);
collect stats on SCMS_SR column(SRC_RPTD_SR_NUMBER_INT);
collect stats on SCMS_SR column(DV_END_CUSTOMER_NAME);
collect stats on SCMS_SR column(C3_CUSTOMER_THEATER_NAME);
collect stats on SCMS_SR column(SOURCE_REPORTED_TAC_COUNTRY_CD);
collect stats on SCMS_SR column(C3_CUST_MARKET_SEGMENT_NAME);


INSERT INTO $$STGDB.SCMS_FINAL
SELECT RMA.FISCAL_YEAR_MONTH_INT,RMA.SRC_RPTD_SR_NUMBER_INT,RMA.DV_END_CUSTOMER_NAME,RMA.C3_CUST_MARKET_SEGMENT_NAME,
RMA.C3_CUSTOMER_THEATER_NAME,RMA.SRC_RPTD_SITE_CNTRY_NAME,sum(RMA.SSC_COST) as SSC_COST
FROM SCMS_RMA RMA
INNER JOIN SCMS_SR SR
ON SR.DV_END_CUSTOMER_NAME=RMA.DV_END_CUSTOMER_NAME
AND RMA.FISCAL_YEAR_MONTH_INT = SR.FISCAL_YEAR_MONTH_INT
--AND SR.SRC_RPTD_SR_NUMBER_INT = RMA.SRC_RPTD_SR_NUMBER_INT
AND SR.SOURCE_REPORTED_TAC_COUNTRY_CD =RMA.SRC_RPTD_SITE_CNTRY_NAME
AND SR.C3_CUSTOMER_THEATER_NAME = RMA.C3_CUSTOMER_THEATER_NAME
QUALIFY ROW_NUMBER() OVER (PARTITION BY RMA.DV_END_CUSTOMER_NAME,RMA.SRC_RPTD_SITE_CNTRY_NAME,RMA.C3_CUSTOMER_THEATER_NAME ORDER BY sum(RMA.SSC_COST)  DESC)=1
--where SR.SRC_RPTD_SR_NUMBER_INT = 689533169
GROUP BY 1,2,3,4,5,6;   


collect stats on $$STGDB.SCMS_FINAL column(FISCAL_YEAR_MONTH_INT);
collect stats on $$STGDB.SCMS_FINAL column(C3_CUST_MARKET_SEGMENT_NAME);
collect stats on $$STGDB.SCMS_FINAL column(SRC_RPTD_SR_NUMBER_INT);
collect stats on $$STGDB.SCMS_FINAL column(DV_END_CUSTOMER_NAME);
collect stats on $$STGDB.SCMS_FINAL column(C3_CUSTOMER_THEATER_NAME);
collect stats on $$STGDB.SCMS_FINAL column(SRC_RPTD_SITE_CNTRY_NAME);

CREATE MULTISET VOLATILE TABLE SL_SR_IB_BASED AS
(
SELECT SR.SRC_RPTD_SR_NUMBER_INT, SR.FISCAL_YEAR_MONTH_INT,COALESCE(PV.CURRENT_SERIAL_NUMBER,000000) AS BK_CUST_RPRTD_PRD_SERIAL_NUM
FROM $$FINLGLVWDB.N_SR_TECH_ASSISTANCE_CNTR_COST SR
INNER JOIN $$STGDB.WI_CCM_TS_MTH_QTR_CNTL CNTL
ON CNTL.FISCAL_YEAR_MONTH_INT = SR.FISCAL_YEAR_MONTH_INT
INNER JOIN (SELECT DISTINCT INCIDENT_NUMBER,CURRENT_SERIAL_NUMBER FROM $$ETLONLYDB.EL_TSS_INCIDENTS_F_V --DL_ADV_SERVICES_LAB.PV_F_TS_INCIDENT_C_V_TRNS_FL
QUALIFY ROW_NUMBER() OVER (PARTITION BY INCIDENT_NUMBER ORDER BY CLOSED_DATE DESC)=1)PV
ON PV.INCIDENT_NUMBER=CAST(SR.SRC_RPTD_SR_NUMBER_INT AS VARCHAR(50))
)  WITH DATA ON COMMIT PRESERVE ROWS; 
 
 COLLECT STATS ON SL_SR_IB_BASED COLUMN ( SRC_RPTD_SR_NUMBER_INT);
COLLECT STATS ON SL_SR_IB_BASED COLUMN ( FISCAL_YEAR_MONTH_INT);
COLLECT STATS ON SL_SR_IB_BASED COLUMN ( BK_CUST_RPRTD_PRD_SERIAL_NUM);

--DROP TABLE IB;
  CREATE MULTISET VOLATILE TABLE IB AS
(
SELECT
DISTINCT 
DU_BK_SERIAL_NUM,IP_SALES_TERRITORY_KEY
 FROM
