) WITH DATA ON COMMIT PRESERVE ROWS;

COLLECT STATS ON IB COLUMN ( DU_BK_SERIAL_NUM);
COLLECT STATS ON IB COLUMN ( IP_SALES_TERRITORY_KEY)
